import{_ as e,o as d,c as o,ae as c}from"./chunks/framework.DTwQaIIa.js";const p=JSON.parse('{"title":"命令与权限","description":"","frontmatter":{},"headers":[],"relativePath":"modules/strengthen/commands.md","filePath":"modules/strengthen/commands.md"}'),r={name:"modules/strengthen/commands.md"};function n(a,t,s,l,i,h){return d(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="命令与权限" tabindex="-1">命令与权限 <a class="header-anchor" href="#命令与权限" aria-label="Permalink to &quot;命令与权限&quot;">​</a></h1><p>EmakiStrengthen 的所有命令都挂在根命令 <code>/emakistrengthen</code> 下面，日常使用可以用别名 <code>/estrengthen</code>。</p><h2 id="命令列表" tabindex="-1">命令列表 <a class="header-anchor" href="#命令列表" aria-label="Permalink to &quot;命令列表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>参数</th><th>做什么</th><th>权限</th></tr></thead><tbody><tr><td><code>/estrengthen help</code></td><td>—</td><td>显示帮助信息</td><td>无</td></tr><tr><td><code>/estrengthen open</code></td><td><code>[配方ID]</code></td><td>打开强化界面</td><td><code>emakistrengthen.use</code></td></tr><tr><td><code>/estrengthen reload</code></td><td>—</td><td>重载所有配置和资源文件</td><td><code>emakistrengthen.reload</code></td></tr><tr><td><code>/estrengthen inspect</code></td><td><code>&lt;玩家&gt;</code></td><td>查看玩家手持装备的强化状态</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen refresh</code></td><td><code>&lt;玩家&gt;</code></td><td>刷新玩家背包中所有装备的强化层展示</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen setstar</code></td><td><code>&lt;玩家&gt; &lt;星级&gt;</code></td><td>设置玩家手持装备的星级</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen clearstate</code></td><td><code>&lt;玩家&gt;</code></td><td>清除玩家手持装备的所有强化数据</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen clearcrack</code></td><td><code>&lt;玩家&gt;</code></td><td>清除玩家手持装备的裂痕</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen givecatalyst</code></td><td><code>&lt;玩家&gt; &lt;催化剂ID&gt; [数量]</code></td><td>给玩家发强化催化剂</td><td><code>emakistrengthen.admin</code></td></tr></tbody></table><h3 id="命令详解" tabindex="-1">命令详解 <a class="header-anchor" href="#命令详解" aria-label="Permalink to &quot;命令详解&quot;">​</a></h3><p><strong><code>/estrengthen open [配方ID]</code></strong></p><p>打开强化 GUI。如果指定了配方 ID，直接用那个配方；不指定的话，放入装备后系统会自动匹配合适的配方。大多数情况下不需要指定配方 ID，让系统自动匹配就行。</p><p><strong><code>/estrengthen reload</code></strong></p><p>重载以下资源：</p><ul><li><code>config.yml</code> 主配置</li><li><code>lang/</code> 语言文件</li><li><code>gui/</code> GUI 配置</li><li><code>recipes/</code> 配方文件</li></ul><p>手动改了配置文件后需要执行这个命令才能生效。</p><p><strong><code>/estrengthen inspect &lt;玩家&gt;</code></strong></p><p>查看指定玩家手持装备的强化详情，会显示：</p><ul><li>当前星级</li><li>锻印等级</li><li>裂痕等级</li><li>累计成功/失败次数</li><li>使用的配方 ID</li><li>最后强化时间</li></ul><p>排查玩家问题时很有用。</p><p><strong><code>/estrengthen setstar &lt;玩家&gt; &lt;星级&gt;</code></strong></p><p>直接把装备设到指定星级。这个命令会做完整的重建：</p><ul><li>更新 PDC 中的 <code>current_star</code></li><li>根据目标星级重建 structured_presentation</li><li>重新写入对应星级的 stats 和 attributes</li><li>重置锻印等级为 0</li></ul><p>适合用来补偿玩家、测试配方效果，或者修复数据异常。</p><p><strong><code>/estrengthen clearstate &lt;玩家&gt;</code></strong></p><p>彻底清除装备上的所有强化数据——星级、锻印、裂痕、审计记录全部清空。装备会恢复到未强化的状态。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p><code>clearstate</code> 不可逆。执行前请确认操作对象正确，建议先用 <code>inspect</code> 看一下当前状态。</p></div><p><strong><code>/estrengthen clearcrack &lt;玩家&gt;</code></strong></p><p>只清除裂痕（<code>crack_level</code> 归零），不影响星级和其他数据。如果你只是想帮玩家修复裂痕而不动星级，用这个命令。</p><p><strong><code>/estrengthen givecatalyst &lt;玩家&gt; &lt;催化剂ID&gt; [数量]</code></strong></p><p>给玩家发放强化催化剂物品，比如强化石、保护道具等。数量不填默认是 1。催化剂 ID 对应的是材料定义中的物品 ID。</p><h2 id="权限节点" tabindex="-1">权限节点 <a class="header-anchor" href="#权限节点" aria-label="Permalink to &quot;权限节点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>权限节点</th><th>说明</th><th>默认</th></tr></thead><tbody><tr><td><code>emakistrengthen.use</code></td><td>使用强化功能</td><td><code>true</code></td></tr><tr><td><code>emakistrengthen.reload</code></td><td>重载配置</td><td><code>op</code></td></tr><tr><td><code>emakistrengthen.admin</code></td><td>管理员权限（包含 inspect、refresh、setstar、clearstate、clearcrack、givecatalyst）</td><td><code>op</code></td></tr></tbody></table><p><code>emakistrengthen.use</code> 默认对所有玩家开放。管理命令统一由 <code>emakistrengthen.admin</code> 控制。</p><div class="tip custom-block"><p class="custom-block-title">提示</p><p><code>emakistrengthen.admin</code> 是一个打包权限，包含了所有管理命令。如果你需要更细粒度的控制（比如只让某个管理员用 inspect 但不能 setstar），可以通过 LuckPerms 等权限插件对子命令单独配置。</p></div>',30)])])}const m=e(r,[["render",n]]);export{p as __pageData,m as default};
